                ? (etEl.GetString() ?? level)
                : level;

            return new LogEntry
            {
                Timestamp = ts,
                Level     = level,
                Message   = message,
                ErrorType = errorType,
                Format    = "json",
                RawLine   = line,
            };
        }
        catch (JsonException)
        {
            return null;
        }
    }

    /// <summary>Normalises log level strings ("WARNING" → "WARN").</summary>
    private static string NormaliseLevel(string raw) =>
        raw.ToUpperInvariant() switch
        {
            "WARNING" => "WARN",
            var v     => v,
        };

    /// <summary>
