     1→// ReportGenerator — produces human-readable table output and JSON files.
     2→//
     3→// TDD progression:
     4→//   RED:   ReportGeneratorTests wouldn't compile (class missing).
     5→//   GREEN: RenderTable(), ToJson(), WriteJsonFile() added to pass tests.
     6→//   REFACTOR: Column widths computed dynamically for a well-aligned table.
     7→
     8→using System.Text;
     9→using System.Text.Json;
    10→using System.Text.Json.Serialization;
    11→
    12→namespace LogAnalyzer.Tests;
    13→
    14→public static class ReportGenerator
    15→{
    16→    private static readonly JsonSerializerOptions JsonOptions = new()
    17→    {
    18→        WriteIndented = true,
    19→        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
    20→        Converters = { new JsonStringEnumConverter() },
    21→    };
    22→
    23→    // ── Human-readable table ─────────────────────────────────────────────────
    24→
    25→    /// <summary>Renders the frequency table as a formatted text table string.</summary>
    26→    public static string RenderTable(IEnumerable<FrequencyRow> rows)
    27→    {
    28→        var list = rows.ToList();
    29→
    30→        if (list.Count == 0)
    31→            return "No errors or warnings found in the log file.\n";
    32→
    33→        // Define columns
    34→        var headers = new[] { "Error Type", "Level", "Count", "First Seen", "Last Seen" };
    35→
    36→        // Format timestamps consistently
    37→        string Fmt(DateTime dt) => dt.ToString("yyyy-MM-dd HH:mm:ss");
    38→
    39→        // Build data rows as string arrays
    40→        var dataRows = list
    41→            .Select(r => new[]
    42→            {
    43→                r.ErrorType,
    44→                r.Level,
    45→                r.Count.ToString(),
    46→                Fmt(r.FirstOccurrence),
    47→                Fmt(r.LastOccurrence),
    48→            })
    49→            .ToList();
    50→
    51→        // Compute column widths (max of header vs data)
    52→        var widths = headers
    53→            .Select((h, i) => Math.Max(h.Length, dataRows.Max(row => row[i].Length)))
    54→            .ToArray();
    55→
    56→        var sb = new StringBuilder();
    57→
    58→        // Header
    59→        sb.AppendLine(BuildSeparator(widths));
    60→        sb.AppendLine(BuildRow(headers, widths));
    61→        sb.AppendLine(BuildSeparator(widths));
    62→
    63→        // Data rows
    64→        foreach (var row in dataRows)
    65→            sb.AppendLine(BuildRow(row, widths));
    66→
    67→        sb.AppendLine(BuildSeparator(widths));
    68→        sb.AppendLine($"Total: {list.Count} distinct error/warning type(s), " +
    69→                      $"{list.Sum(r => r.Count)} total occurrence(s).");
    70→
    71→        return sb.ToString();
    72→    }
    73→
    74→    // ── JSON output ──────────────────────────────────────────────────────────
    75→
    76→    /// <summary>Serialises the frequency rows to a JSON string.</summary>
    77→    public static string ToJson(IEnumerable<FrequencyRow> rows) =>
    78→        JsonSerializer.Serialize(rows.ToList(), JsonOptions);
    79→
    80→    /// <summary>Writes the JSON report to a file, creating/overwriting it.</summary>
    81→    public static void WriteJsonFile(IEnumerable<FrequencyRow> rows, string filePath)
    82→    {
    83→        var dir = Path.GetDirectoryName(filePath);
    84→        if (!string.IsNullOrEmpty(dir))
    85→            Directory.CreateDirectory(dir);
    86→
    87→        File.WriteAllText(filePath, ToJson(rows));
    88→    }
    89→
    90→    // ── Private helpers ──────────────────────────────────────────────────────
    91→
    92→    private static string BuildSeparator(int[] widths) =>
    93→        "+" + string.Join("+", widths.Select(w => new string('-', w + 2))) + "+";
    94→
    95→    private static string BuildRow(string[] cells, int[] widths)
    96→    {
    97→        var cols = cells
    98→            .Select((c, i) => " " + c.PadRight(widths[i]) + " ")
    99→            .ToArray();
   100→        return "|" + string.Join("|", cols) + "|";
   101→    }
   102→}
