     1→// LogAnalyzer.cs — .NET 10 file-based app (run with: dotnet run LogAnalyzer.cs)
     2→//
     3→// Parses a mixed-format log file (syslog-style + JSON-structured lines),
     4→// extracts error and warning entries, produces a frequency table with first/last
     5→// occurrence timestamps, and writes both a human-readable table and a JSON report.
     6→//
     7→// Usage:
     8→//   dotnet run LogAnalyzer.cs <input-log-file> [output-json-file]
     9→//
    10→// If output-json-file is omitted, it defaults to <input-log-file>.report.json
    11→
    12→// ── .NET 10 file-based app: top-level statements below are the entry point ──
    13→
    14→using System.Globalization;
    15→using System.Text;
    16→using System.Text.Json;
    17→using System.Text.Json.Serialization;
    18→using System.Text.RegularExpressions;
    19→
    20→// ── Entry point ──────────────────────────────────────────────────────────────
    21→
    22→if (args.Length < 1)
    23→{
    24→    Console.Error.WriteLine("Usage: dotnet run LogAnalyzer.cs <log-file> [output-json]");
    25→    Console.Error.WriteLine("  log-file    : path to mixed-format log file");
    26→    Console.Error.WriteLine("  output-json : path for JSON report (default: <log-file>.report.json)");
    27→    return 1;
    28→}
    29→
    30→var inputPath  = args[0];
    31→var outputPath = args.Length >= 2 ? args[1] : inputPath + ".report.json";
    32→
    33→if (!File.Exists(inputPath))
    34→{
    35→    Console.Error.WriteLine($"Error: file not found: {inputPath}");
    36→    return 1;
    37→}
    38→
    39→Console.WriteLine($"Parsing log file: {inputPath}");
    40→
    41→var lines   = File.ReadAllLines(inputPath);
    42→var parser  = new AppLogParser();
    43→var entries = parser.ParseLines(lines).ToList();
    44→
    45→Console.WriteLine($"Parsed {entries.Count} valid log entries " +
    46→                  $"({entries.Count(e => e.Level == "ERROR")} errors, " +
    47→                  $"{entries.Count(e => e.Level == "WARN")} warnings, " +
    48→                  $"{entries.Count(e => e.Level is "INFO" or "DEBUG")} info/debug)");
    49→
    50→var rows  = AppFrequencyAnalyzer.Analyze(entries).ToList();
    51→var table = AppReportGenerator.RenderTable(rows);
    52→
    53→// Print human-readable table to console
    54→Console.WriteLine();
    55→Console.Write(table);
    56→
    57→// Write JSON report
    58→AppReportGenerator.WriteJsonFile(rows, outputPath);
    59→Console.WriteLine($"JSON report written to: {outputPath}");
    60→
    61→return 0;
    62→
    63→// ── Models ───────────────────────────────────────────────────────────────────
    64→
    65→/// <summary>Represents a single parsed log entry.</summary>
    66→class AppLogEntry
    67→{
    68→    public DateTime Timestamp { get; init; }
    69→    public string   Level     { get; init; } = string.Empty;
    70→    public string   Message   { get; init; } = string.Empty;
    71→    /// <summary>
    72→    /// Error/warning category: from "error_type" in JSON, or first word of syslog message.
    73→    /// </summary>
    74→    public string   ErrorType { get; init; } = string.Empty;
    75→    /// <summary>"syslog" or "json"</summary>
    76→    public string   Format    { get; init; } = string.Empty;
    77→}
    78→
    79→/// <summary>One row in the frequency report.</summary>
    80→class AppFrequencyRow
    81→{
    82→    public string   ErrorType       { get; init; } = string.Empty;
    83→    public string   Level           { get; init; } = string.Empty;
    84→    public int      Count           { get; init; }
    85→    public DateTime FirstOccurrence { get; init; }
    86→    public DateTime LastOccurrence  { get; init; }
    87→}
    88→
    89→// ── Parser ───────────────────────────────────────────────────────────────────
    90→
    91→/// <summary>
    92→/// Parses individual log lines in syslog or JSON format.
    93→/// Unrecognised lines are silently skipped.
    94→/// </summary>
    95→class AppLogParser
    96→{
    97→    // Matches: "Jan 15 10:23:45 hostname app[pid]: LEVEL: message"
    98→    private static readonly Regex SyslogRegex = new(
    99→        @"^(\w{3}\s+\d{1,2}\s+\d{2}:\d{2}:\d{2})\s+\S+\s+\S+\[\d+\]:\s+(ERROR|WARN(?:ING)?|INFO|DEBUG):\s+(.+)$",
   100→        RegexOptions.Compiled);
   101→
   102→    public AppLogEntry? ParseLine(string line)
   103→    {
   104→        if (string.IsNullOrWhiteSpace(line) || line.TrimStart().StartsWith('#'))
   105→            return null;
   106→
   107→        if (line.TrimStart().StartsWith('{'))
   108→            return TryParseJson(line);
   109→
   110→        return TryParseSyslog(line);
   111→    }
   112→
   113→    public IEnumerable<AppLogEntry> ParseLines(IEnumerable<string> lines)
   114→    {
   115→        foreach (var line in lines)
   116→        {
   117→            var entry = ParseLine(line);
   118→            if (entry is not null) yield return entry;
   119→        }
   120→    }
   121→
   122→    private static AppLogEntry? TryParseSyslog(string line)
   123→    {
   124→        var m = SyslogRegex.Match(line);
   125→        if (!m.Success) return null;
   126→
   127→        var tsStr   = m.Groups[1].Value;
   128→        var level   = Normalise(m.Groups[2].Value);
   129→        var message = m.Groups[3].Value.Trim();
   130→
   131→        if (!DateTime.TryParse(
   132→                tsStr + " " + DateTime.UtcNow.Year,
   133→                CultureInfo.InvariantCulture,
   134→                DateTimeStyles.AllowWhiteSpaces,
   135→                out var ts))
   136→            return null;
   137→
   138→        var firstWord = message.Split(' ', StringSplitOptions.RemoveEmptyEntries).FirstOrDefault() ?? message;
   139→
   140→        return new AppLogEntry
   141→        {
   142→            Timestamp = ts, Level = level, Message = message,
   143→            ErrorType = firstWord, Format = "syslog",
   144→        };
   145→    }
   146→
   147→    private static AppLogEntry? TryParseJson(string line)
   148→    {
   149→        try
   150→        {
   151→            using var doc  = JsonDocument.Parse(line);
   152→            var root = doc.RootElement;
   153→
   154→            if (!root.TryGetProperty("level",     out var lvlEl)  ||
   155→                !root.TryGetProperty("message",   out var msgEl)  ||
   156→                !root.TryGetProperty("timestamp", out var tsEl))
   157→                return null;
   158→
   159→            var level   = Normalise(lvlEl.GetString() ?? "");
   160→            var message = msgEl.GetString() ?? "";
   161→
   162→            if (!DateTime.TryParse(
   163→                    tsEl.GetString(),
   164→                    CultureInfo.InvariantCulture,
   165→                    DateTimeStyles.RoundtripKind,
   166→                    out var ts)) return null;
   167→
   168→            var errorType = root.TryGetProperty("error_type", out var etEl)
   169→                ? (etEl.GetString() ?? level)
   170→                : level;
   171→
   172→            return new AppLogEntry
   173→            {
   174→                Timestamp = ts, Level = level, Message = message,
   175→                ErrorType = errorType, Format = "json",
   176→            };
   177→        }
   178→        catch (JsonException) { return null; }
   179→    }
   180→
   181→    private static string Normalise(string raw) =>
   182→        raw.ToUpperInvariant() == "WARNING" ? "WARN" : raw.ToUpperInvariant();
   183→}
   184→
   185→// ── Frequency analyzer ───────────────────────────────────────────────────────
   186→
   187→static class AppFrequencyAnalyzer
   188→{
   189→    private static readonly HashSet<string> Included =
   190→        new(StringComparer.OrdinalIgnoreCase) { "ERROR", "WARN" };
   191→
   192→    public static IEnumerable<AppFrequencyRow> Analyze(IEnumerable<AppLogEntry> entries) =>
   193→        entries
   194→            .Where(e => Included.Contains(e.Level))
   195→            .GroupBy(e => (e.ErrorType, e.Level))
   196→            .Select(g => new AppFrequencyRow
   197→            {
   198→                ErrorType       = g.Key.ErrorType,
   199→                Level           = g.Key.Level,
   200→                Count           = g.Count(),
   201→                FirstOccurrence = g.Min(e => e.Timestamp),
   202→                LastOccurrence  = g.Max(e => e.Timestamp),
   203→            })
   204→            .OrderByDescending(r => r.Count)
   205→            .ThenBy(r => r.ErrorType);
   206→}
   207→
   208→// ── Report generator ─────────────────────────────────────────────────────────
   209→
   210→static class AppReportGenerator
   211→{
   212→    private static readonly JsonSerializerOptions JsonOpts = new()
   213→    {
   214→        WriteIndented        = true,
   215→        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
   216→        Converters           = { new JsonStringEnumConverter() },
   217→    };
   218→
   219→    public static string RenderTable(IEnumerable<AppFrequencyRow> rows)
   220→    {
   221→        var list = rows.ToList();
   222→        if (list.Count == 0) return "No errors or warnings found in the log file.\n";
   223→
   224→        string Fmt(DateTime dt) => dt.ToString("yyyy-MM-dd HH:mm:ss");
   225→
   226→        var headers  = new[] { "Error Type", "Level", "Count", "First Seen", "Last Seen" };
   227→        var dataRows = list.Select(r => new[]
   228→        {
   229→            r.ErrorType, r.Level, r.Count.ToString(),
   230→            Fmt(r.FirstOccurrence), Fmt(r.LastOccurrence),
   231→        }).ToList();
   232→
   233→        var widths = headers
   234→            .Select((h, i) => Math.Max(h.Length, dataRows.Max(row => row[i].Length)))
   235→            .ToArray();
   236→
   237→        var sb = new StringBuilder();
   238→        sb.AppendLine(Sep(widths));
   239→        sb.AppendLine(Row(headers, widths));
   240→        sb.AppendLine(Sep(widths));
   241→        foreach (var r in dataRows) sb.AppendLine(Row(r, widths));
   242→        sb.AppendLine(Sep(widths));
   243→        sb.AppendLine($"Total: {list.Count} distinct type(s), {list.Sum(r => r.Count)} occurrence(s).");
   244→        return sb.ToString();
   245→    }
   246→
   247→    public static string ToJson(IEnumerable<AppFrequencyRow> rows) =>
   248→        JsonSerializer.Serialize(rows.ToList(), JsonOpts);
   249→
   250→    public static void WriteJsonFile(IEnumerable<AppFrequencyRow> rows, string path)
   251→    {
   252→        var dir = Path.GetDirectoryName(path);
   253→        if (!string.IsNullOrEmpty(dir)) Directory.CreateDirectory(dir);
   254→        File.WriteAllText(path, ToJson(rows));
   255→    }
   256→
   257→    private static string Sep(int[] widths) =>
   258→        "+" + string.Join("+", widths.Select(w => new string('-', w + 2))) + "+";
   259→
   260→    private static string Row(string[] cells, int[] widths) =>
   261→        "|" + string.Join("|", cells.Select((c, i) => " " + c.PadRight(widths[i]) + " ")) + "|";
   262→}
